param(
    [string]$Root = $PSScriptRoot
)

$files = @{}

$files['assets\toggle_off.ico'] = @'

'@

$files['assets\toggle_off.png'] = @'

'@

$files['assets\toggle_on.ico'] = @'

'@

$files['assets\toggle_on.png'] = @'

'@

$files['assets\vesper.ico'] = @'

'@

$files['assets\vesper.png'] = @'

'@

foreach ($relativePath in $files.Keys) {
    $targetPath = Join-Path $Root $relativePath
    $targetDir = Split-Path -Parent $targetPath
    if (-not (Test-Path -LiteralPath $targetDir)) {
        New-Item -ItemType Directory -Path $targetDir -Force | Out-Null
    }
    $bytes = [Convert]::FromBase64String($files[$relativePath].Trim())
    [System.IO.File]::WriteAllBytes($targetPath, $bytes)
    Write-Host "Wrote $relativePath ($($bytes.Length) bytes)"
}
